def gen(rng, size):
    import string
    n = min(size, 100)
    chars = []
    letter_count = 0
    for _ in range(n):
        if letter_count > 0 and rng.random() < 0.4:
            chars.append(str(rng.randint(0, 9)))
            letter_count -= 1
        else:
            chars.append(rng.choice(string.ascii_lowercase))
            letter_count += 1
    return [''.join(chars)]

