class Solution:
    def clearDigits(self, s):
        lst = list(s)
        changed = True
        while changed:
            changed = False
            for i, c in enumerate(lst):
                if c.isdigit():
                    # find closest non-digit to the left
                    for j in range(i - 1, -1, -1):
                        if lst[j] != '' and not lst[j].isdigit():
                            lst[j] = ''
                            break
                    lst[i] = ''
                    changed = True
                    break
        return ''.join(lst)

